fun min(): Int? {
  if (stack.isEmpty()) return null
  return min
}

fun peek(): Int? {
  if (stack.isEmpty()) return null
  if (stack.last() &lt; min) return min
  return stack.last()
}

fun push(e: Int) {
  if (stack.isEmpty()) {
    stack.addLast(e)
    min = e
  } else if (e &lt; min) {
    stack.addLast(2 * e - min)
    min = e
  } else {
    stack.addLast(e)
  }
}

fun pop(): Int? {
  if (stack.isEmpty()) return null
  if (stack.last() &lt; min) {
    return min.also {
      min = 2 * min - stack.removeLast()
    }
  }
  return stack.removeLast()
}
